import re

def parse_duration(s: str) -> int:
    """
    Parse a duration string (e.g., '2h30m', '45m', '1h', '90s') into the total number of seconds.
    Raises ValueError for invalid input.
    """
    if not isinstance(s, str):
        raise ValueError("Input must be a string")
    s = s.strip()
    if not s:
        raise ValueError("Empty string is not a valid duration")
    # Ensure the string consists only of digit+unit groups
    if not re.fullmatch(r'(?:\d+[hms])+', s, re.IGNORECASE):
        raise ValueError(f"Invalid duration format: {s!r}")
    total_seconds = 0
    for value, unit in re.findall(r'(\d+)([hms])', s, re.IGNORECASE):
        num = int(value)
        unit = unit.lower()
        if unit == 'h':
            total_seconds += num * 3600
        elif unit == 'm':
            total_seconds += num * 60
        elif unit == 's':
            total_seconds += num
        else:
            # This branch should never be reached due to regex, but keep for safety
            raise ValueError(f"Unknown unit {unit!r} in duration")
    return total_seconds
